/**
 * Unit Tests: Rate Limiter (memory-only, sem Redis)
 * Testa o rate limiter in-memory (src/lib/rate-limit.ts)
 *
 * Nota: Estes testes validam o comportamento do limiter sem Redis.
 * O Redis é mockado como indisponível para testar o fallback in-memory.
 */

// Mock Redis para forçar fallback in-memory
jest.mock('ioredis', () => {
  return jest.fn().mockImplementation(() => ({
    on: jest.fn(),
    eval: jest.fn().mockRejectedValue(new Error('Redis unavailable')),
    multi: jest.fn().mockReturnValue({
      get: jest.fn().mockReturnThis(),
      pttl: jest.fn().mockReturnThis(),
      exec: jest.fn().mockResolvedValue([[null, null], [null, -1]]),
    }),
    quit: jest.fn(),
  }));
});

// Mock logger to prevent side effects
jest.mock('@/lib/logger', () => ({
  logger: {
    debug: jest.fn(),
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
  },
}));

import { globalRateLimiter, checkRateLimit } from '@/lib/rate-limit';

describe('globalRateLimiter', () => {
  describe('sync check (in-memory)', () => {
    it('should allow requests within limit', () => {
      const key = `test-${Date.now()}-allow`;
      const result = globalRateLimiter.check(key);
      expect(result.success).toBe(true);
      expect(result.remaining).toBeLessThanOrEqual(result.limit);
    });

    it('should block after limit exceeded', () => {
      const key = `test-${Date.now()}-block`;
      // Configure limiter with low limit for test
      globalRateLimiter.configure({ limit: 3, windowMs: 10_000 });

      // Exhaust the limit
      globalRateLimiter.check(key);
      globalRateLimiter.check(key);
      globalRateLimiter.check(key);

      // 4th request should be blocked
      const result = globalRateLimiter.check(key);
      expect(result.success).toBe(false);
      expect(result.remaining).toBe(0);

      // Reset to defaults
      globalRateLimiter.configure({ limit: 100, windowMs: 60_000 });
    });

    it('should return remaining count', () => {
      const key = `test-${Date.now()}-remaining`;
      globalRateLimiter.configure({ limit: 5, windowMs: 10_000 });

      const r1 = globalRateLimiter.check(key);
      expect(r1.remaining).toBe(4);

      const r2 = globalRateLimiter.check(key);
      expect(r2.remaining).toBe(3);

      // Reset
      globalRateLimiter.configure({ limit: 100, windowMs: 60_000 });
    });
  });

  describe('configure', () => {
    it('should update limit', () => {
      globalRateLimiter.configure({ limit: 50 });
      expect(globalRateLimiter.limit).toBe(50);
      // Reset
      globalRateLimiter.configure({ limit: 100 });
    });

    it('should update windowMs', () => {
      globalRateLimiter.configure({ windowMs: 30_000 });
      expect(globalRateLimiter.windowMs).toBe(30_000);
      // Reset
      globalRateLimiter.configure({ windowMs: 60_000 });
    });
  });
});

describe('checkRateLimit (async, fallback to memory)', () => {
  it('should return a decision object', async () => {
    const key = `async-${Date.now()}`;
    const result = await checkRateLimit(key, 10, 60_000);

    expect(result).toHaveProperty('allowed');
    expect(result).toHaveProperty('retryAfterSec');
    expect(result).toHaveProperty('remaining');
    expect(result).toHaveProperty('limit');
    expect(result).toHaveProperty('resetAtMs');
    expect(result).toHaveProperty('source');
  });

  it('should use memory source when Redis unavailable', async () => {
    // With Redis mocked as unavailable, should fallback
    const key = `async-memory-${Date.now()}`;
    const result = await checkRateLimit(key, 10, 60_000);
    // Source will be memory or fail-open/fail-closed
    expect(['memory', 'fail-open', 'fail-closed']).toContain(result.source);
  });

  it('should allow first request', async () => {
    const key = `async-first-${Date.now()}`;
    const result = await checkRateLimit(key, 10, 60_000);
    expect(result.allowed).toBe(true);
    expect(result.retryAfterSec).toBe(0);
  });
});
